// Disabled because jest-dom matchers (toHaveAttribute/toHaveTextContent) are designed for
// HTML and do not work reliably on strict XML elements generated by serialization.
/* eslint-disable jest-dom/prefer-to-have-attribute, jest-dom/prefer-to-have-text-content */
import Mapping from '../../declarations/mapping.js';
import { QTIDeclaration } from '../../QTIDeclaration.js';
import { CAPABILITY } from '../../declarations/index.js';
import { parseXML, reparse } from '../testUtils.js';
import { MAPPING_WITH_BOUNDS_XML, MAPPING_WITH_CI_XML, SIMPLE_MAPPING_XML } from './fixtures.js';

function makeDeclaration() {
  return new QTIDeclaration({
    identifier: 'RESPONSE',
    baseType: 'identifier',
    cardinality: 'single',
  });
}

function parseMappingXml(xmlString) {
  return parseXML(xmlString).querySelector('qti-mapping');
}

describe('Mapping', () => {
  describe('constructor', () => {
    it('stores the provided data', () => {
      const data = { defaultValue: 0, lowerBound: null, upperBound: null, entries: [] };
      const m = new Mapping(data, makeDeclaration());
      expect(m.get()).toEqual(data);
    });
  });

  describe('fromXML', () => {
    it('parses default-value attribute', () => {
      const node = parseMappingXml(SIMPLE_MAPPING_XML);
      const declaration = makeDeclaration();
      const m = Mapping.fromXML(node, declaration);
      expect(m.get().defaultValue).toBe(0);
    });

    it('defaults default-value to 0 when absent', () => {
      const node = parseMappingXml(`
        <qti-response-declaration identifier="X" base-type="identifier" cardinality="single">
          <qti-mapping/>
        </qti-response-declaration>
      `);
      const declaration = makeDeclaration();
      const m = Mapping.fromXML(node, declaration);
      expect(m.get().defaultValue).toBe(0);
    });

    it('parses lower-bound attribute', () => {
      const node = parseMappingXml(MAPPING_WITH_BOUNDS_XML);
      const declaration = makeDeclaration();
      const m = Mapping.fromXML(node, declaration);
      expect(m.get().lowerBound).toBe(-2);
    });

    it('parses upper-bound attribute', () => {
      const node = parseMappingXml(MAPPING_WITH_BOUNDS_XML);
      const declaration = makeDeclaration();
      const m = Mapping.fromXML(node, declaration);
      expect(m.get().upperBound).toBe(5);
    });

    it('sets lowerBound to null when absent', () => {
      const node = parseMappingXml(SIMPLE_MAPPING_XML);
      const declaration = makeDeclaration();
      const m = Mapping.fromXML(node, declaration);
      expect(m.get().lowerBound).toBeNull();
    });

    it('sets upperBound to null when absent', () => {
      const node = parseMappingXml(SIMPLE_MAPPING_XML);
      const declaration = makeDeclaration();
      const m = Mapping.fromXML(node, declaration);
      expect(m.get().upperBound).toBeNull();
    });

    it('parses map entries', () => {
      const node = parseMappingXml(SIMPLE_MAPPING_XML);
      const declaration = makeDeclaration();
      const m = Mapping.fromXML(node, declaration);
      expect(m.get().entries).toHaveLength(2);
      expect(m.get().entries[0]).toEqual({
        mapKey: 'ChoiceA',
        mappedValue: 1,
        caseSensitive: true,
      });
      expect(m.get().entries[1]).toEqual({
        mapKey: 'ChoiceB',
        mappedValue: -0.5,
        caseSensitive: true,
      });
    });

    it('parses case-sensitive="false" on entries', () => {
      const node = parseMappingXml(MAPPING_WITH_CI_XML);
      const declaration = makeDeclaration();
      const m = Mapping.fromXML(node, declaration);
      expect(m.get().entries[0].caseSensitive).toBe(false);
      expect(m.get().entries[1].caseSensitive).toBe(true);
    });

    it('registers itself as MAPPING capability', () => {
      const node = parseMappingXml(SIMPLE_MAPPING_XML);
      const declaration = makeDeclaration();
      Mapping.fromXML(node, declaration);
      expect(declaration._capabilities[CAPABILITY.MAPPING]).toBeDefined();
      expect(declaration.mapping).not.toBeNull();
    });
  });

  describe('getXML', () => {
    it('produces a qti-mapping element', () => {
      const data = { defaultValue: 0, lowerBound: null, upperBound: null, entries: [] };
      expect(new Mapping(data, makeDeclaration()).getXML().tagName).toBe('qti-mapping');
    });

    it('emits default-value attribute', () => {
      const data = { defaultValue: -1, lowerBound: null, upperBound: null, entries: [] };
      expect(new Mapping(data, makeDeclaration()).getXML().getAttribute('default-value')).toBe(
        '-1',
      );
    });

    it('emits lower-bound only when not null', () => {
      const withBound = { defaultValue: 0, lowerBound: -2, upperBound: null, entries: [] };
      const withoutBound = { defaultValue: 0, lowerBound: null, upperBound: null, entries: [] };
      expect(new Mapping(withBound, makeDeclaration()).getXML().getAttribute('lower-bound')).toBe(
        '-2',
      );
      expect(
        new Mapping(withoutBound, makeDeclaration()).getXML().hasAttribute('lower-bound'),
      ).toBe(false);
    });

    it('emits upper-bound only when not null', () => {
      const withBound = { defaultValue: 0, lowerBound: null, upperBound: 5, entries: [] };
      expect(new Mapping(withBound, makeDeclaration()).getXML().getAttribute('upper-bound')).toBe(
        '5',
      );
    });

    it('produces qti-map-entry children', () => {
      const data = {
        defaultValue: 0,
        lowerBound: null,
        upperBound: null,
        entries: [
          { mapKey: 'ChoiceA', mappedValue: 1, caseSensitive: true },
          { mapKey: 'ChoiceB', mappedValue: -0.5, caseSensitive: true },
        ],
      };
      const node = new Mapping(data, makeDeclaration()).getXML();
      const entries = [...node.querySelectorAll('qti-map-entry')];
      expect(entries).toHaveLength(2);
      expect(entries[0].getAttribute('map-key')).toBe('ChoiceA');
      expect(entries[0].getAttribute('mapped-value')).toBe('1');
    });

    it('only emits case-sensitive attr when false', () => {
      const data = {
        defaultValue: 0,
        lowerBound: null,
        upperBound: null,
        entries: [
          { mapKey: 'a', mappedValue: 1, caseSensitive: false },
          { mapKey: 'b', mappedValue: 1, caseSensitive: true },
        ],
      };
      const entries = [
        ...new Mapping(data, makeDeclaration()).getXML().querySelectorAll('qti-map-entry'),
      ];
      expect(entries[0].getAttribute('case-sensitive')).toBe('false');
      expect(entries[1].hasAttribute('case-sensitive')).toBe(false);
    });

    it('round-trips fromXML → getXML preserves all attributes via DOM', () => {
      const node = parseMappingXml(MAPPING_WITH_BOUNDS_XML);
      const declaration = makeDeclaration();
      const m = Mapping.fromXML(node, declaration);
      const out = m.getXML();
      expect(out.getAttribute('default-value')).toBe('-1');
      expect(out.getAttribute('lower-bound')).toBe('-2');
      expect(out.getAttribute('upper-bound')).toBe('5');
      expect(out.querySelector('qti-map-entry').getAttribute('map-key')).toBe('A');
    });
  });

  describe('full XML output (QTI compatibility)', () => {
    it('serializes to well-formed XML that re-parses without error', () => {
      const node = parseMappingXml(MAPPING_WITH_BOUNDS_XML);
      const m = Mapping.fromXML(node, makeDeclaration());
      expect(() => reparse(m.getXML())).not.toThrow();
    });

    it('re-parsed XML has qti-mapping root tag', () => {
      const reparsed = reparse(
        Mapping.fromXML(parseMappingXml(SIMPLE_MAPPING_XML), makeDeclaration()).getXML(),
      );
      expect(reparsed.tagName).toBe('qti-mapping');
    });

    it('re-parsed XML has correct number of qti-map-entry children', () => {
      const reparsed = reparse(
        Mapping.fromXML(parseMappingXml(SIMPLE_MAPPING_XML), makeDeclaration()).getXML(),
      );
      expect(reparsed.querySelectorAll('qti-map-entry').length).toBe(2);
    });

    it('re-parsed XML preserves map-key and mapped-value attributes', () => {
      const reparsed = reparse(
        Mapping.fromXML(parseMappingXml(SIMPLE_MAPPING_XML), makeDeclaration()).getXML(),
      );
      const first = reparsed.querySelector('qti-map-entry');
      expect(first.getAttribute('map-key')).toBe('ChoiceA');
      expect(first.getAttribute('mapped-value')).toBe('1');
    });

    it('re-parsed XML preserves bounds from full round-trip', () => {
      const reparsed = reparse(
        Mapping.fromXML(parseMappingXml(MAPPING_WITH_BOUNDS_XML), makeDeclaration()).getXML(),
      );
      expect(reparsed.getAttribute('lower-bound')).toBe('-2');
      expect(reparsed.getAttribute('upper-bound')).toBe('5');
    });

    // Non-ASCII map-key values (e.g. Arabic or CJK identifiers authored in i18n contexts)
    it('correctly encodes non-ASCII map-key values (i18n)', () => {
      const data = {
        defaultValue: 0,
        lowerBound: null,
        upperBound: null,
        entries: [{ mapKey: '选择甲', mappedValue: 1, caseSensitive: true }],
      };
      const reparsed = reparse(new Mapping(data, makeDeclaration()).getXML());
      expect(reparsed.querySelector('qti-map-entry').getAttribute('map-key')).toBe('选择甲');
    });
  });
});
